    28→	) {
    29→		this._proxy = extHostContext.getProxy(ExtHostContext.ExtHostDiagnostics);
    30→
    31→		this._markerListener = this._markerService.onMarkerChanged(this._forwardMarkers, this);
    32→		this._fileChangeListener = this._fileService.onDidFilesChange(event => {
    33→			// When files change on disk (e.g. git branch switch), clear stale diagnostics
    34→			// for affected files so extensions can provide fresh diagnostics
    35→			for (const owner of this._activeOwners) {
    36→				const markers = this._markerService.read({ owner });
    37→				for (const marker of markers) {
    38→					if (event.contains(marker.resource, FileChangeType.UPDATED, FileChangeType.DELETED)) {
    39→						this._markerService.changeOne(owner, marker.resource, []);
    40→					}
    41→				}
    42→			}
    43→		});
    44→	}
    45→
    46→	dispose(): void {
    47→		this._markerListener.dispose();
    48→		this._fileChangeListener.dispose();
    49→		this._activeOwners.forEach(owner => this._markerService.changeAll(owner, []));
    50→		this._activeOwners.clear();
    51→	}
    52→
    53→	private _forwardMarkers(resources: readonly URI[]): void {
    54→		const data: [UriComponents, IMarkerData[]][] = [];
    55→		for (const resource of resources) {
    56→			const allMarkerData = this._markerService.read({ resource });
    57→			if (allMarkerData.length === 0) {
    58→				data.push([resource, []]);
    59→			} else {
    60→				const forgeinMarkerData = allMarkerData.filter(marker => !this._activeOwners.has(marker.owner));
    61→				if (forgeinMarkerData.length > 0) {
    62→					data.push([resource, forgeinMarkerData]);
    63→				}
    64→			}
    65→		}
    66→		if (data.length > 0) {
    67→			this._proxy.$acceptMarkersChange(data);
    68→		}
    69→	}
    70→
    71→	$changeMany(owner: string, entries: [UriComponents, IMarkerData[]][]): void {
    72→		for (const entry of entries) {
    73→			const [uri, markers] = entry;
    74→			if (markers) {
    75→				for (const marker of markers) {
    76→					if (marker.relatedInformation) {
    77→						for (const relatedInformation of marker.relatedInformation) {
    78→							relatedInformation.resource = URI.revive(relatedInformation.resource);
    79→						}
    80→					}
