    87→		}
    88→		this._activeOwners.add(owner);
    89→	}
    90→
    91→	$clear(owner: string): void {
    92→		this._markerService.changeAll(owner, []);
    93→		this._activeOwners.delete(owner);
    94→	}
    95→}
